import { Credentials } from './credentials';
/**
 * A credentials set of the `PUBLIC_CERTIFICATE` type.
 */
export interface PublicCertificateCredentials extends Credentials {
    /**
     * The certificate in the string format.
     */
    certificate: string;
    /**
     * The certificate format.
     */
    certificateFormat: 'PEM' | 'PKCS12' | 'UNKNOWN';
    /**
     * The password of the credential (not supported).
     */
    password: string;
}
